"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["48150"],{68266(e){e.exports=JSON.parse('{"tag":{"label":"ecommerce","permalink":"/sysanalyst-kb.github.io/docs/tags/ecommerce","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"specialization/ecommerce-retail-path","title":"E-commerce & Retail \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C","description":"E-commerce-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043E\u043D\u043B\u0430\u0439\u043D-\u043F\u0440\u043E\u0434\u0430\u0436\u0430\u043C\u0438 Wildberries, Ozon, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u043A\u0435\u0442, AliExpress.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-retail-path"},{"id":"specialization/ecommerce-analytics","title":"E-commerce \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u0438 \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432\u0430\u044F \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430","description":"E-commerce \u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A\u0430 \u2014 \u0441\u0431\u043E\u0440, \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 \u0438 \u0432\u0438\u0437\u0443\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F \u043C\u0435\u0442\u0440\u0438\u043A CDP (Customer Data Platform), \u043F\u0440\u043E\u0434\u0443\u043A\u0442\u043E\u0432\u044B\u0435 \u0432\u043E\u0440\u043E\u043D\u043A\u0438 (funnel), \u043A\u043E\u0433\u043E\u0440\u0442\u043D\u044B\u0439 \u0430\u043D\u0430\u043B\u0438\u0437 (cohort), ABC-XYZ \u0430\u043D\u0430\u043B\u0438\u0437 \u0430\u0441\u0441\u043E\u0440\u0442\u0438\u043C\u0435\u043D\u0442\u0430. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0441\u043E\u0431\u044B\u0442\u0438\u044F, \u0434\u0430\u0448\u0431\u043E\u0440\u0434\u044B \u0438 rules \u0434\u043B\u044F \u0430\u043B\u0435\u0440\u0442\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-analytics"},{"id":"specialization/ecommerce-oms","title":"OMS \u2014 Order Management System","description":"OMS (Order Management System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0437\u0430\u043A\u0430\u0437\u0430\u043C\u0438, \u044F\u0434\u0440\u043E e-commerce \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B. \u0417\u0430\u043A\u0430\u0437 \u043F\u0440\u043E\u0445\u043E\u0434\u0438\u0442 \u0447\u0435\u0440\u0435\u0437 12+ \u0441\u0442\u0430\u0442\u0443\u0441\u043E\u0432 \u0441\u0432\u044F\u0437\u044B\u0432\u0430\u0435\u0442 \u043A\u0430\u0442\u0430\u043B\u043E\u0433 (\u0447\u0442\u043E \u043F\u0440\u043E\u0434\u0430\u043B\u0438), WMS (\u0447\u0442\u043E \u0441\u043E\u0431\u0440\u0430\u043B\u0438), TMS (\u0447\u0442\u043E \u0434\u043E\u0441\u0442\u0430\u0432\u0438\u043B\u0438) \u0438 \u043F\u043B\u0430\u0442\u0451\u0436\u043D\u044B\u0439 \u0448\u043B\u044E\u0437 (\u0447\u0442\u043E \u043E\u043F\u043B\u0430\u0442\u0438\u043B\u0438). \u0412 \u043F\u0438\u043A\u0435 (Black Friday) OMS \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0442\u044C 10 000+ \u0437\u0430\u043A\u0430\u0437\u043E\u0432/\u0447\u0430\u0441.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-oms"},{"id":"specialization/ecommerce-catalog","title":"\u041A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u043E\u0432\u0430\u0440\u043E\u0432 \u0438 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0438\u043D\u0432\u0435\u043D\u0442\u0430\u0440\u0438\u0437\u0430\u0446\u0438\u0435\u0439","description":"\u041A\u0430\u0442\u0430\u043B\u043E\u0433 \u0442\u043E\u0432\u0430\u0440\u043E\u0432 \u2014 \u0446\u0435\u043D\u0442\u0440\u0430\u043B\u044C\u043D\u0430\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C e-commerce. \u0421\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 (\u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438, \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u044B, SKU), \u043F\u043E\u0438\u0441\u043A (Elasticsearch), \u0438\u043D\u0432\u0435\u043D\u0442\u0430\u0440\u0438\u0437\u0430\u0446\u0438\u044F (\u043E\u0441\u0442\u0430\u0442\u043A\u0438, \u0440\u0435\u0437\u0435\u0440\u0432\u044B) \u0438 \u0446\u0435\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435. \u0422\u0438\u043F\u0438\u0447\u043D\u0430\u044F \u043E\u0448\u0438\u0431\u043A\u0430 \u2014 \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A\u0430\u0442\u0430\u043B\u043E\u0433 \u043A\u0430\u043A \u043F\u043B\u043E\u0441\u043A\u0443\u044E \u0442\u0430\u0431\u043B\u0438\u0446\u0443. \u0423 Wildberries > 10M \u0430\u043A\u0442\u0438\u0432\u043D\u044B\u0445 SKU, \u043F\u043E\u0438\u0441\u043A \u2014 \u043C\u0438\u043B\u043B\u0438\u0441\u0435\u043A\u0443\u043D\u0434\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u0430\u0442\u0440\u0438\u0431\u0443\u0442\u044B, \u0441\u0432\u044F\u0437\u0438 \u043C\u0435\u0436\u0434\u0443 \u0442\u043E\u0432\u0430\u0440\u0430\u043C\u0438, \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043F\u043E\u0438\u0441\u043A\u0430 \u0438 \u0441\u0438\u043D\u0445\u0440\u043E\u043D\u0438\u0437\u0430\u0446\u0438\u044E \u0441 WMS.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-catalog"},{"id":"specialization/ecommerce-marketplace","title":"\u041C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u2014 \u043C\u043E\u0434\u0435\u043B\u044C marketplace","description":"\u041C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u2014 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430, \u0433\u0434\u0435 \u043F\u0440\u043E\u0434\u0430\u0432\u0446\u044B (\u0442\u0440\u0435\u0442\u044C\u0438 \u043B\u0438\u0446\u0430) \u0442\u043E\u0440\u0433\u0443\u044E\u0442 \u0447\u0435\u0440\u0435\u0437 \u0432\u0430\u0448 \u043A\u0430\u043D\u0430\u043B. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043C\u043E\u0434\u0435\u043B\u0438 Wildberries, Ozon, \u042F\u043D\u0434\u0435\u043A\u0441.\u041C\u0430\u0440\u043A\u0435\u0442.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-marketplace"},{"id":"specialization/ecommerce-loyalty","title":"\u0421\u0438\u0441\u0442\u0435\u043C\u044B \u043B\u043E\u044F\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0432 e-commerce","description":"\u0421\u0438\u0441\u0442\u0435\u043C\u0430 \u043B\u043E\u044F\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u2014 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0430 \u0443\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u043A\u043B\u0438\u0435\u043D\u0442\u043E\u0432 \u0447\u0435\u0440\u0435\u0437 \u0431\u043E\u043D\u0443\u0441\u044B, \u043A\u044D\u0448\u0431\u044D\u043A, \u0443\u0440\u043E\u0432\u043D\u0438, \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u044F. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0431\u0430\u043B\u043B\u044C\u043D\u0430\u044F (1 \u0431\u0430\u043B\u043B = 1 \u0440\u0443\u0431\u043B\u044C), \u043A\u044D\u0448\u0431\u044D\u043A (% \u043E\u0442 \u043F\u043E\u043A\u0443\u043F\u043A\u0438), tiered (\u0443\u0440\u043E\u0432\u043D\u0438 Bronze \u2192 Silver \u2192 Gold), \u043F\u043E\u0434\u043F\u0438\u0441\u043E\u0447\u043D\u0430\u044F (Amazon Prime). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043D\u0430\u0447\u0438\u0441\u043B\u0435\u043D\u0438\u044F/\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u044F, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 OMS \u0438 Promo Engine.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-loyalty"},{"id":"specialization/ecommerce-fulfillment","title":"\u0424\u0443\u043B\u0444\u0438\u043B\u043C\u0435\u043D\u0442 \u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0430 e-commerce","description":"\u0424\u0443\u043B\u0444\u0438\u043B\u043C\u0435\u043D\u0442 \u2014 \u0432\u0441\u0451, \u0447\u0442\u043E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0441 \u0437\u0430\u043A\u0430\u0437\u043E\u043C \u043F\u043E\u0441\u043B\u0435 \u043E\u043F\u043B\u0430\u0442\u044B WMS (\u0441\u043A\u043B\u0430\u0434) \u0438 TMS (\u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442). \u0418\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F D1 (\u0441\u0435\u0433\u043E\u0434\u043D\u044F), D2 (\u0437\u0430\u0432\u0442\u0440\u0430), D3+ (\u0434\u043E 7 \u0434\u043D\u0435\u0439). Last-mile \u2014 \u0434\u043E 60% \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u0438 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438. \u0412\u043E\u0437\u0432\u0440\u0430\u0442\u044B \u2014 \u0434\u043E 15% \u0432 fashion.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-fulfillment"},{"id":"specialization/ecommerce-pricing","title":"\u0426\u0435\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435, \u043F\u0440\u043E\u043C\u043E \u0438 \u0441\u043A\u0438\u0434\u043A\u0438","description":"\u0426\u0435\u043D\u043E\u043E\u0431\u0440\u0430\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u0432 e-commerce \u2014 \u0441\u043B\u043E\u0436\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0441 \u043F\u0435\u0440\u0435\u043A\u0440\u044B\u0432\u0430\u044E\u0449\u0438\u043C\u0438\u0441\u044F \u0441\u043A\u0438\u0434\u043A\u0430\u043C\u0438, \u043F\u0440\u043E\u043C\u043E\u043A\u043E\u0434\u0430\u043C\u0438, \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u0430\u043C\u0438 \u043B\u043E\u044F\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0438 \u0434\u0438\u043D\u0430\u043C\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0446\u0435\u043D\u0430\u043C\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0434\u043E\u043B\u0436\u0435\u043D \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u0440\u0430\u0441\u0447\u0451\u0442\u0430 \u0444\u0438\u043D\u0430\u043B\u044C\u043D\u043E\u0439 \u0446\u0435\u043D\u044B, \u043F\u0440\u0438\u043E\u0440\u0438\u0442\u0435\u0442\u044B \u0441\u043A\u0438\u0434\u043E\u043A (stacking) \u0438 \u0438\u0437\u0431\u0435\u0433\u0430\u0442\u044C \xab\u0441\u0445\u043B\u043E\u043F\u044B\u0432\u0430\u043D\u0438\u044F\xbb (\u043A\u043E\u0433\u0434\u0430 \u0441\u043A\u0438\u0434\u043A\u0438 \u0434\u0435\u043B\u0430\u044E\u0442 \u0446\u0435\u043D\u0443 \u043E\u0442\u0440\u0438\u0446\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0439). \u041D\u0430 \u043A\u0440\u0443\u043F\u043D\u044B\u0445 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441\u0430\u0445 \u0446\u0435\u043D\u0430 \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u0436\u0434\u044B\u0435 15 \u043C\u0438\u043D \u043F\u043E\u0434 \u0432\u043B\u0438\u044F\u043D\u0438\u0435\u043C \u0441\u043F\u0440\u043E\u0441\u0430, \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0442\u043E\u0432 \u0438 \u043E\u0441\u0442\u0430\u0442\u043A\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/ecommerce-pricing"}],"unlisted":false}}')}}]);